import (
	"fmt"
	"sync"
)

func processJob(id int, wg *sync.WaitGroup) {
	defer wg.Done()
	fmt.Printf("Job %d done\n", id)
}

func main() {
	var wg sync.WaitGroup

	for i := 1; i <= 3; i++ {
		wg.Add(1)
		go processJob(i, &wg)
	}

	wg.Wait()
	fmt.Println("All jobs complete")
